+                call_outcome(
+                    py,
+                    &numpy_trimcoef,
+                    &PyTuple::new(py, [coeffs.clone()])?,
+                    Some(&bad_tol_kwargs),
+                )?
+            );
+
+            Ok(())
+        });
+    }
